1101	    /// let oper1 = sel.recv(&r1);
1102	    /// let oper2 = sel.recv(&r2);
1103	    ///
1104	    /// // The second operation will be selected because it becomes ready first.
1105	    /// match sel.ready_timeout(Duration::from_millis(500)) {
1106	    ///     Err(_) => panic!("should not have timed out"),
1107	    ///     Ok(i) if i == oper1 => assert_eq!(r1.try_recv(), Ok(10)),
1108	    ///     Ok(i) if i == oper2 => assert_eq!(r2.try_recv(), Ok(20)),
1109	    ///     Ok(_) => unreachable!(),
1110	    /// }
1111	    /// # t1.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
1112	    /// # t2.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
1113	    /// ```
